pub fn new(inner: T) -> FramedWrite<T, B> {
    let chain_threshold = if inner.is_write_vectored() {
        CHAIN_THRESHOLD
    } else {
        CHAIN_THRESHOLD_WITHOUT_VECTORED_IO
    };
    FramedWrite {
        inner,
        final_flush_done: false,
        encoder: Encoder {
            hpack: hpack::Encoder::default(),
            buf: Cursor::new(BytesMut::with_capacity(DEFAULT_BUFFER_CAPACITY)),
            next: None,
            last_data_frame: None,
            max_frame_size: frame::DEFAULT_MAX_FRAME_SIZE,
            chain_threshold,
            min_buffer_capacity: chain_threshold + frame::HEADER_LEN,
        },
    }
}

pub async fn connect_tcp<Ws: WithSocket>(
    host: &str,
    port: u16,
    with_socket: Ws,
) -> crate::Result<Ws::Output> {
    #[cfg(feature = "_rt-tokio")]
    if crate::rt::rt_tokio::available() {
        return Ok(with_socket
            .with_socket(tokio::net::TcpStream::connect((host, port)).await?)
            .await);
    }

    cfg_if! {
        if #[cfg(feature = "_rt-async-io")] {
            Ok(with_socket.with_socket(connect_tcp_async_io(host, port).await?).await)
        } else {
            crate::rt::missing_rt((host, port, with_socket))
        }
    }
}

fn file_path(&self, source_span: Span) -> syn::Result<Option<String>> {
    if let QuerySrc::File(ref file) = *self {
        let path = crate::common::resolve_path(file, source_span)?
            .canonicalize()
            .map_err(|e| syn::Error::new(source_span, e))?;

        Ok(Some(
            path.to_str()
                .ok_or_else(|| {
                    syn::Error::new(
                        source_span,
                        "query file path cannot be represented as a string",
                    )
                })?
                .to_string(),
        ))
    } else {
        Ok(None)
    }
}

fn encode_with(&self, buf: &mut Vec<u8>, context: Capabilities) -> Result<(), crate::Error> {
    // truncation is intended
    #[allow(clippy::cast_possible_truncation)]
    buf.extend(&(context.bits() as u32).to_le_bytes());
    buf.extend(&self.max_packet_size.to_le_bytes());
    buf.push(self.charset);

    // reserved: string<19>
    buf.extend(&[0_u8; 19]);

    if context.contains(Capabilities::MYSQL) {
        // reserved: string<4>
        buf.extend(&[0_u8; 4]);
    } else {
        // extended client capabilities (MariaDB-specified): int<4>
        buf.extend(&((context.bits() >> 32) as u32).to_le_bytes());
    }

    Ok(())
}

pub fn update(&mut self, cb: impl FnOnce(&mut Option<T>)) {
    match &mut self.inner {
        Inner::Threadsafe(value) => cb(value),
        Inner::Local(value) => match value {
            Some(sw) => {
                cb(sw.deref_mut());
                if sw.is_none() {
                    *value = None;
                }
            }
            None => {
                let mut inner = None;
                cb(&mut inner);
                if let Some(inner) = inner {
                    *value = Some(SendWrapper::new(Some(inner)));
                }
            }
        },
    }
}

fn into_response(self) -> Response {
    let (code, value) = match self {
        Self::Logout(err) => {
            (StatusCode::BAD_REQUEST, json::Error::from(err))
        }
        Self::Login(err) => {
            (StatusCode::BAD_REQUEST, json::Error::from(err))
        }
        Self::Credentials(err) => {
            (StatusCode::BAD_REQUEST, json::Error::from(err))
        }
        Self::CreateUser(err) => {
            (StatusCode::BAD_REQUEST, json::Error::from(err))
        }
        Self::Auth(err) => {
            (StatusCode::UNAUTHORIZED, json::Error::from(err))
        }
    };
    (code, Json(value)).into_response()
}

pub fn dont_match_smooshed_static_segments() {
    let routes = RouteDefs::<_>::new((
        NestedRoute::new(StaticSegment(""), || ()),
        NestedRoute::new(StaticSegment("users"), || ()),
        NestedRoute::new(
            (StaticSegment("users"), StaticSegment("id")),
            || (),
        ),
        NestedRoute::new(WildcardSegment("any"), || ()),
    ));

    let matched = routes.match_route("/users");
    assert!(matches!(matched, Some(EitherOf4::B(..))));

    let matched = routes.match_route("/users/id");
    assert!(matches!(matched, Some(EitherOf4::C(..))));

    let matched = routes.match_route("/usersid");
    assert!(matches!(matched, Some(EitherOf4::D(..))));
}

