fn try_new_req_multipart(
    path: &str,
    accepts: &str,
    body: Self::FormData,
    method: Method,
) -> Result<Self, E> {
    match method {
        Method::POST => CLIENT.post(path),
        Method::PUT => CLIENT.put(path),
        Method::PATCH => CLIENT.patch(path),
        m => {
            return Err(E::from_server_fn_error(
                ServerFnErrorErr::UnsupportedRequestMethod(m.to_string()),
            ))
        }
    }
    .header(ACCEPT, accepts)
    .multipart(body)
    .build()
    .map_err(|e| ServerFnErrorErr::Request(e.to_string()).into_app_error())
}

fn l0410_deep_creation(b: &mut Bencher) {
    use l0410::*;
    let runtime = create_runtime();

    b.iter(|| {
        create_scope(runtime, |cx| {
            let signal = create_rw_signal(cx, 0);
            let mut memos = Vec::<Memo<usize>>::new();
            for _ in 0..1000usize {
                if let Some(prev) = memos.last().copied() {
                    memos.push(create_memo(cx, move |_| prev.get() + 1));
                } else {
                    memos.push(create_memo(cx, move |_| signal.get() + 1));
                }
            }
        })
        .dispose()
    });

    runtime.dispose();
}

pub(crate) fn create_enum_from_entity<E>(_: E, backend: DbBackend) -> Vec<TypeCreateStatement>
where
    E: EntityTrait,
{
    if matches!(backend, DbBackend::MySql | DbBackend::Sqlite) {
        return Vec::new();
    }
    let mut vec = Vec::new();
    for col in E::Column::iter() {
        let col_def = col.def();
        let col_type = col_def.get_column_type();
        if !matches!(col_type, ColumnType::Enum { .. }) {
            continue;
        }
        if let Some(stmt) = create_enum_from_column_type(&col_type) {
            vec.push(stmt);
        }
    }
    vec
}

