pub(crate) fn push_front(&mut self, val: L::Handle) {
    // The value should not be dropped, it is being inserted into the list
    let val = ManuallyDrop::new(val);
    let ptr = L::as_raw(&val);
    assert_ne!(self.head, Some(ptr));
    unsafe {
        L::pointers(ptr).as_mut().set_next(self.head);
        L::pointers(ptr).as_mut().set_prev(None);

        if let Some(head) = self.head {
            L::pointers(head).as_mut().set_prev(Some(ptr));
        }

        self.head = Some(ptr);

        if self.tail.is_none() {
            self.tail = Some(ptr);
        }
    }
}

pub fn bind<P>(path: P) -> io::Result<UnixListener>
    where
        P: AsRef<Path>,
    {
        // For now, we handle abstract socket paths on linux here.
        #[cfg(any(target_os = "linux", target_os = "android"))]
        let addr = {
            let os_str_bytes = path.as_ref().as_os_str().as_bytes();
            if os_str_bytes.starts_with(b"\0") {
                StdSocketAddr::from_abstract_name(&os_str_bytes[1..])?
            } else {
                StdSocketAddr::from_pathname(path)?
            }
        };
        #[cfg(not(any(target_os = "linux", target_os = "android")))]
        let addr = StdSocketAddr::from_pathname(path)?;

        let addr = SocketAddr::from(addr);
        UnixListener::bind_addr(&addr)
    }

pub(crate) fn new(park: IoStack, clock: &Clock) -> (Driver, Handle) {
    let time_source = TimeSource::new(clock);

    let handle = Handle {
        time_source,
        inner: Inner::Traditional {
            state: Mutex::new(InnerState {
                next_wake: None,
                wheel: wheel::Wheel::new(),
            }),
            is_shutdown: AtomicBool::new(false),

            #[cfg(feature = "test-util")]
            did_wake: AtomicBool::new(false),
        },
    };

    let driver = Driver { park };

    (driver, handle)
}

fn prewarm_fd_table(target: i32) -> std::io::Result<()> {
    use std::os::unix::io::{FromRawFd, OwnedFd};

    let dev_null = std::fs::File::open("/dev/null")?;
    let raw = unsafe {
        libc::fcntl(
            std::os::unix::io::AsRawFd::as_raw_fd(&dev_null),
            libc::F_DUPFD_CLOEXEC,
            target,
        )
    };
    if raw < 0 {
        return Err(std::io::Error::last_os_error());
    }

    // Close both FDs. The table capacity persists.
    let _owned = unsafe { OwnedFd::from_raw_fd(raw) };
    drop(dev_null);

    Ok(())
}

