fn fetch_update_action<F, T>(&self, mut f: F) -> T
    where
        F: FnMut(Snapshot) -> (T, Option<Snapshot>),
    {
        let mut curr = self.load();

        loop {
            let (output, next) = f(curr);
            let next = match next {
                Some(next) => next,
                None => return output,
            };

            let res = self.val.compare_exchange(curr.0, next.0, AcqRel, Acquire);

            match res {
                Ok(_) => return output,
                Err(actual) => curr = Snapshot(actual),
            }
        }
    }

pub(crate) fn try_init(&mut self, probe: &mut Probe) -> io::Result<bool> {
    if self.uring.is_some() {
        // Already initialized.
        return Ok(false);
    }

    let uring = IoUring::new(DEFAULT_RING_SIZE)?;

    match uring.submitter().register_probe(probe) {
        Ok(_) => {}
        Err(e) if e.raw_os_error() == Some(libc::EINVAL) => {
            // The kernel does not support IORING_REGISTER_PROBE.
            return Err(io::Error::from_raw_os_error(libc::ENOSYS));
        }
        Err(e) => return Err(e),
    }

    self.uring.replace(uring);

    Ok(true)
}

pub(crate) unsafe fn try_push(
    &self,
    block: &mut NonNull<Block<T>>,
    success: Ordering,
    failure: Ordering,
) -> Result<(), NonNull<Block<T>>> {
    // Safety: caller guarantees that `block` is valid.
    unsafe { block.as_mut() }.header.start_index =
        self.header.start_index.wrapping_add(BLOCK_CAP);

    let next_ptr = self
        .header
        .next
        .compare_exchange(ptr::null_mut(), block.as_ptr(), success, failure)
        .unwrap_or_else(|x| x);

    match NonNull::new(next_ptr) {
        Some(next_ptr) => Err(next_ptr),
        None => Ok(()),
    }
}

fn wildcard_qvalue(headers: &http::HeaderMap) -> Option<QValue> {
    headers
        .get_all(http::header::ACCEPT_ENCODING)
        .iter()
        .filter_map(|hval| hval.to_str().ok())
        .flat_map(|s| s.split(','))
        .find_map(|v| {
            let mut v = v.splitn(2, ';');
            let coding = v.next().unwrap().trim();
            if coding != "*" {
                return None;
            }
            let qval = if let Some(qval) = v.next() {
                QValue::parse(qval.trim())?
            } else {
                QValue::one()
            };
            Some(qval)
        })
}
